const raw = $input.first().json.output[0].content[0].text;

let cleaned = raw.trim();

if (cleaned.startsWith("```")) {
  cleaned = cleaned
    .replace(/```json/g, "")
    .replace(/```/g, "")
    .trim();
}

const parsed = JSON.parse(cleaned);

const STORY_ID = `story_${Date.now()}`;
const BUCKET = "BD-Pages";
const SUPABASE_URL = "https://wddatxgqhdiosuhcztex.supabase.co";

const CHARACTER_LOCK = `
Main character reference (STRICT — MUST remain identical in every image):

8-year-old girl
short straight black bob haircut
small red ribbon on the LEFT side of her head
large emerald green eyes
soft round child face
blue adventure tunic with golden trim
brown leather boots
small side satchel
glowing star-shaped pendant around her neck

DO NOT change character design.
DO NOT change outfit.
DO NOT move ribbon.
`;

const flattenedPages = [];

for (const step of parsed.steps) {

  for (const choice of step.choices) {

    const fileName = `step-${step.step}-${choice.choice_id}.png`;
    const storagePath = `${STORY_ID}/step-${step.step}/${fileName}`;

    flattenedPages.push({
      storyId: STORY_ID,
      step: step.step,
      choiceId: choice.choice_id,
      pageId: `step-${step.step}-${choice.choice_id}`,

      bucket: BUCKET,
      fileName,
      storagePath,
      supabaseUrl: SUPABASE_URL,

      sceneSummary: step.scene_summary,
      panels: step.panels,

      geminiPrompt: `
Create a full children manga page illustration.

STYLE:
Soft pastel Japanese children manga style.
No text.
No speech bubbles.
No typography.

${CHARACTER_LOCK}

SCENE:
${step.scene_summary}

CHOICE CONTEXT:
${choice.choice_label}

PANELS:
${JSON.stringify(step.panels, null, 2)}

Maintain strict character consistency.
`
    });
  }
}

return flattenedPages.map(p => ({ json: p }));

